        // category IN ["single"]
        String vectorExpr = this.converter.convertExpression(new Expression(IN, new Key("category"), new Value(List.of("single"))));
        assertThat(vectorExpr).isEqualTo("{\"category\": {\"$in\": [\"single\"]}}");
    }

    @Test
    public void testZeroValues() {
        // quantity == 0 AND price > 0
        String vectorExpr = this.converter.convertExpression(new Expression(AND, new Expression(EQ, new Key("quantity"), new Value(0)), new Expression(GT, new Key("price"), new Value(0))));
        assertThat(vectorExpr).isEqualTo("{\"$and\": [{\"quantity\": {\"$eq\": 0}},{\"price\": {\"$gt\": 0}}]}");
    }

    @Test
    public void testComplexNestedExpression() {
        // (priority >= 1 AND priority <= 5) OR (urgent == true AND category NIN ["low",
        // "medium"])
        String vectorExpr = this.converter.convertExpression(new Expression(OR, new Group(new Expression(AND, new Expression(GTE, new Key("priority"), new Value(1)), new Expression(LTE, new Key("priority"), new Value(5)))), new Group(new Expression(AND, new Expression(EQ, new Key("urgent"), new Value(true)), new Expression(NIN, new Key("category"), new Value(List.of("low", "medium")))))));
        assertThat(vectorExpr).isEqualTo("{\"$or\": [{\"$and\": [{\"priority\": {\"$gte\": 1}},{\"priority\": {\"$lte\": 5}}]},{\"$and\": [{\"urgent\": {\"$eq\": true}},{\"category\": {\"$nin\": [\"low\",\"medium\"]}}]}]}");
    }
}
